using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>().ToContainer("Products");

        // EF9 renamed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", so we must preserve the old name
        // to keep both EF queries and direct SQL (c.Discriminator) working.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        // EF9 no longer embeds the discriminator in the JSON id property.
        // Existing documents have id values like "Product|123"; without this flag
        // EF9 would generate just "123", breaking FindAsync and point-reads.
        modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);

        // REMOVED: HasIndex ã EF9 Cosmos provider now throws at startup.
        // Cosmos DB indexing is managed via the container's indexing policy
        // (Azure Portal / Bicep / Terraform), not through EF Core.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

